class Solution:
    def isRationalEqual(self, s: str, t: str) -> bool:
        def toFloat(s: str) -> float:
            if '(' in s:
                i, j = s.index('('), s.index(')')
                rep = s[i:j]
                s = s.replace(s[i-1:j+1], '')
                s += rep * 20
            return float(s)
        return toFloat(s) == toFloat(t)
